      // and overriding getName() via proxy is too complex for this test.
      // Instead, we use a workaround with anonymous classes in the desired package name.
      // But Java does not allow that easily, so rely on class names with prefixes.

      // Instead, use a proxy class with a custom ClassLoader is too complex here.
      // So we simulate by testing with strings in isAndroidType and the other prefixes only.

    } catch (Exception ignored) {}
  }
}
